-- One-time bulk import of ROGA LI expenses from the owner-provided PDF
-- (ROGA__Expenses_1.pdf), covering 04/01/2026 - 02/07/2026.
-- Run this once in the Supabase SQL editor.
--
-- Row count: 283
-- Sum of amounts: EUR 115622.22


-- Verification: run this separately afterwards to confirm the import.
-- Expected: count = 283, total ≈ €115,622.22
select count(*) as row_count, sum(amount) as total_amount
from public.expenses
where boat_id = '193bdf92-8c6f-4665-a95c-57d3ab3cb105'
  and expense_date between '2026-01-01' and '2026-07-31';
